mapper.select:
SELECT nu.id, nu.notice_id, nu.read_status, nu.read_time, n.title, n.content, n.type, n.sender_name, n.publish_time FROM system_notice_user nu INNER JOIN system_notice n ON nu.notice_id = n.id AND n.del_flag = 0 WHERE nu.user_id = #{userId} AND nu.del_flag = 0 AND n.status = 1
AND n.type = #{type}
AND nu.read_status = #{readStatus}
AND n.title LIKE CONCAT('%', #{title}, '%')
ORDER BY nu.read_status ASC, n.publish_time DESC
